using namespace std;

// Function to obtain the minimum possible 
// sum from the array by K reductions 
int minSum(int a[], int n, int k)
{
    priority_queue < int > q;

    // Insert elements into the MaxHeap 
    for (int i = 0; i < n; i++)
    {
        q.push(a[i]);
    }

    while (!q.empty() && k > 0)
    {
        int top = q.top() / 2;

        // Remove the maximum             
        q.pop();

        // Insert maximum / 2 
        q.push(top);
        k -= 1;
    }

    // Stores the sum of remaining elements
    int sum = 0;
    while (!q.empty())
    {
        sum += q.top();
        q.pop();
    }
    return sum;
}

