#include <stdio.h>
#include <stdlib.h>

// Function to obtain the minimum possible 
// sum from the array by K reductions 
int minSum(int a[], int n, int k)
{
    // Create a max heap using the priority queue concept
    int *heap = (int *)malloc(n * sizeof(int));
    int heapSize = 0;

    // Function to insert an element into the max heap
    void insert(int value) {
        heap[heapSize++] = value;
        int i = heapSize - 1;

        // Bubble up the new value to maintain max heap property
        while (i != 0) {
            int parent = (i - 1) / 2;
            if (heap[parent] < heap[i]) {
                // Swap parent and current node
                int temp = heap[parent];
                heap[parent] = heap[i];
                heap[i] = temp;
                i = parent;
            } else {
                break;
            }
        }
    }

    // Function to remove the maximum element from the max heap
    int extractMax() {
        if (heapSize == 0) return -1; // Handle empty heap
        int max = heap[0];
        heap[0] = heap[--heapSize];

        // Bubble down the new root to maintain max heap property
        int i = 0;
        while (i < heapSize) {
            int left = 2 * i + 1;
            int right = 2 * i + 2;
            int largest = i;

            if (left < heapSize && heap[left] > heap[largest]) {
                largest = left;
            }
            if (right < heapSize && heap[right] > heap[largest]) {
                largest = right;
            }
            if (largest != i) {
                // Swap with the largest child
                int temp = heap[i];
                heap[i] = heap[largest];
                heap[largest] = temp;
                i = largest;
            } else {
                break;
            }
        }
        return max;
    }

    // Insert elements into the max heap
    for (int i = 0; i < n; i++)
    {
        insert(a[i]);
    }

    while (k > 0 && heapSize > 0)
    {
        int maxElement = extractMax();
        int reducedElement = maxElement / 2;

        // Insert the reduced element back into the heap
        insert(reducedElement);
        k--;
    }

    // Stores the sum of remaining elements
    int sum = 0;
    while (heapSize > 0)
    {
        sum += extractMax();
    }

    free(heap); // Free the allocated memory
    return sum;
}

// Driver code
int main()
{
    int n;
    scanf("%d", &n);
    int k;
    scanf("%d", &k);

    int *a = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }

    printf("%d\n", minSum(a, n, k));

    free(a); // Free the allocated memory
    return 0;
}

