import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef
{
    // Function to obtain the minimum possible sum from the array by K reductions
    public static int minSum(int a[], int n, int k)
    {
        // MaxHeap using PriorityQueue
        PriorityQueue<Integer> q = new PriorityQueue<>(Collections.reverseOrder());

        // Insert elements into the MaxHeap
        for (int i = 0; i < n; i++)
        {
            q.add(a[i]);
        }

        // Perform k reductions
        while (!q.isEmpty() && k > 0)
        {
            int top = q.poll() / 2; // Divide the top element by 2
            q.add(top); // Add the reduced element back
            k -= 1;
        }

        // Calculate the sum of the remaining elements
        int sum = 0;
        while (!q.isEmpty())
        {
            sum += q.poll();
        }

        return sum;
    }

    public static void main (String[] args) throws java.lang.Exception
    {
        // Input scanner
        Scanner sc = new Scanner(System.in);

        // Reading input
        int n = sc.nextInt();  // Array size
        int k = sc.nextInt();  // Number of reductions

        int[] a = new int[n];
        for (int i = 0; i < n; i++) {
            a[i] = sc.nextInt();  // Array elements
        }

        // Output the result
        System.out.println(minSum(a, n, k));

        sc.close();
    }
}

